import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";
import { SyncedStateServer, syncedStateRoutes } from "rwsdk/use-synced-state/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { ChatPage } from "@/app/pages/chat";

export type AppContext = {};

export { SyncedStateServer };

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  syncedStateRoutes(() => env.SYNCED_STATE_SERVER),
  render(Document, [
    route("/", Home),
    route("/chat/:roomId", ChatPage),
  ]),
]);

"use client";

import { useState } from "react";
import { useSyncedState } from "rwsdk/use-synced-state/client";

export function ChatRoom({ roomId }: { roomId: string }) {
  const [messages, setMessages] = useSyncedState<string[]>([], "messages", roomId);
  const [inputValue, setInputValue] = useState("");

  const handleSend = () => {
    const trimmed = inputValue.trim();
    if (trimmed) {
      setMessages((prev: string[]) => [...prev, trimmed]);
      setInputValue("");
    }
  };

  const handleClear = () => {
    setMessages([]);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "Enter") {
      handleSend();
    }
  };

  return (
    <div>
      <div
        style={{
          height: "300px",
          overflowY: "auto",
          border: "1px solid #ccc",
          padding: "8px",
          marginBottom: "8px",
        }}
      >
        {messages.map((msg, index) => (
          <div key={index} data-testid="chat-message">
            {msg}
          </div>
        ))}
      </div>
      <div style={{ display: "flex", gap: "8px" }}>
        <input
          data-testid="chat-input"
          type="text"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        <button data-testid="send-btn" onClick={handleSend}>
          Send
        </button>
        <button data-testid="clear-btn" onClick={handleClear}>
          Clear
        </button>
      </div>
    </div>
  );
}

import { ChatRoom } from "@/app/components/ChatRoom";

export function ChatPage({ params }: { params: { roomId: string } }) {
  return (
    <div>
      <h1>Room: {params.roomId}</h1>
      <ChatRoom roomId={params.roomId} />
    </div>
  );
}

